import { useState, useEffect } from 'react';
import AnimatedPage from '../components/AnimatedPage';
import AuraSelect from '../components/AuraSelect';
import SortableFilterTable from '../components/SortableFilterTable';
import { ResearchSubNav } from './ResearchDashboardPage';
import { api } from '../utils/api';
import s from './ResearchPortfolioPage.module.css';

const ALLOC_COLS = [
  { key: 'Strategy', label: 'Strategy', width: 180, mono: false },
  { key: 'Weight', label: 'Weight', width: 160, render: (v) => {
    const pct = parseFloat(String(v).replace('%', ''));
    return (
      <div className={s.allocBar}>
        <div className={s.allocTrack}>
          <div className={s.allocFill} style={{ width: `${Math.min(pct, 100)}%` }} />
        </div>
        <span className={s.allocValue}>{v}</span>
      </div>
    );
  }},
  { key: 'Fitness', label: 'Fitness', width: 80, align: 'right' },
  { key: 'Direction', label: 'Dir', width: 70, render: v => (
    <span className={v === 'long' ? s.dirLong : v === 'short' ? s.dirShort : s.dirNeutral}>
      {v?.toUpperCase() || '--'}
    </span>
  )},
  { key: 'Confidence', label: 'Confidence', width: 100, render: v => {
    const cls = v === 'high' ? s.confHigh : v === 'medium' ? s.confMedium : v === 'low' ? s.confLow : s.confDefault;
    return <span className={cls}>{v || '--'}</span>;
  }},
  { key: 'Risk/Trade', label: 'Risk/Trade', width: 100, align: 'right' },
];

function BotCard({ name, bot }) {
  if (!bot) return null;
  return (
    <div className={s.botCard}>
      <div className={s.botCardHeader}>
        <h3 className={s.botName}>{name}</h3>
        <span className={bot.safe_for_monday ? s.safeBadgeSafe : s.safeBadgeUnsafe}>
          {bot.safe_for_monday ? 'SAFE FOR MONDAY' : 'NOT SAFE'}
        </span>
      </div>

      <div className={s.metricsRow}>
        <div>
          <div className={s.metricLabel}>Combined Fitness</div>
          <div className={s.metricValueLg}>{bot.combined_fitness ?? '--'}</div>
        </div>
        <div>
          <div className={s.metricLabel}>Risk Posture</div>
          <div className={`${s.metricValueSm} ${bot.risk_posture === 'normal' ? s.riskNormal : s.riskElevated}`}>
            {bot.risk_posture || '--'}
          </div>
        </div>
        <div>
          <div className={s.metricLabel}>Strategies</div>
          <div className={s.metricValueLg}>{bot.strategy_count ?? '--'}</div>
        </div>
      </div>

      {/* Allocation table */}
      <SortableFilterTable
        columns={ALLOC_COLS}
        data={bot.allocations || []}
        defaultSortKey="Weight"
        defaultSortDir="desc"
        emptyMessage="No allocations"
      />

      {/* Warnings */}
      {bot.warnings?.length > 0 && (
        <div className={s.warningsWrap}>
          {bot.warnings.map((w, i) => (
            <div key={i} className={s.warning}>
              {w}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default function ResearchPortfolioPage() {
  const [data, setData] = useState(null);
  const [botFilter, setBotFilter] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api('/research/portfolio').then(d => { setData(d); setLoading(false); });
  }, []);

  const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
  const allBots = data?.bots || {};
  const bots = Object.fromEntries(Object.entries(allBots).filter(([k]) => !PAPER_BOTS.has(k.toLowerCase())));
  const botNames = Object.keys(bots);
  const botOptions = [{ value: '', label: 'All Bots' }, ...botNames.map(n => ({ value: n, label: n }))];
  const displayBots = botFilter ? botNames.filter(n => n === botFilter) : botNames;

  return (
    <AnimatedPage>
      <div className={s.page}>
        <ResearchSubNav />

        <div className={s.headerRow}>
          <h1 className={s.title}>
            Portfolio Allocation
          </h1>
          <AuraSelect options={botOptions} value={botFilter} onChange={setBotFilter} placeholder="Select bot" />
        </div>

        {loading && <div className={s.loadingMsg}>Loading portfolio data...</div>}

        {!loading && botNames.length === 0 && (
          <div className={s.emptyMsg}>No portfolio recommendation found</div>
        )}

        {/* Bot cards */}
        <div className={s.botGrid}>
          {displayBots.map(name => (
            <BotCard key={name} name={name} bot={bots[name]} />
          ))}
        </div>

        {/* Weight distribution comparison when All */}
        {!botFilter && botNames.length > 1 && (
          <div className={s.comparisonSection}>
            <h2 className={s.comparisonTitle}>
              Allocation Comparison
            </h2>
            <div className={s.comparisonCard}>
              {botNames.map(name => {
                const allocs = bots[name]?.allocations || [];
                const hues = [210, 260, 160, 30, 340, 190, 280, 140];
                return (
                  <div key={name} className={s.compBotGroup}>
                    <div className={s.compBotName}>
                      {name}
                    </div>
                    <div className={s.compBarTrack}>
                      {allocs.map((a, i) => {
                        const pct = parseFloat(String(a.Weight || '0').replace('%', ''));
                        const hue = hues[i % hues.length];
                        return (
                          <div
                            key={i}
                            title={`${a.Strategy}: ${a.Weight}`}
                            className={s.compBarSegment}
                            style={{
                              width: `${pct}%`,
                              background: `hsl(${hue}, 60%, 55%)`,
                            }}
                          >
                            {pct >= 10 ? a.Strategy?.slice(0, 8) : ''}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </AnimatedPage>
  );
}
